+
+#[test]
+fn recvmsg_invalid_fd_fails() {
+    let mut buf = [0u8; 16];
+    let mut iov = libc::iovec {
+        iov_base: buf.as_mut_ptr() as *mut c_void,
+        iov_len: buf.len(),
+    };
+    let mut hdr: libc::msghdr = unsafe { std::mem::zeroed() };
+    hdr.msg_iov = &mut iov;
+    hdr.msg_iovlen = 1;
+
+    let rc = unsafe { socket_abi::recvmsg(-1, &mut hdr, 0) };
